 64→function validateFolderData(data: unknown): boolean {
 65→  if (typeof data !== 'object' || data === null) return false;
 66→  const d = data as Record<string, unknown>;
 67→  return Array.isArray(d.folders) && typeof d.folderContents === 'object';
 68→}
