153→  constructor() {
154→    // Create storage adapter based on browser (Factory Pattern)
155→    this.storage = createFolderStorageAdapter();
156→    this.debug(`Using storage backend: ${this.storage.getBackendName()}`);
157→
158→    // Initialize backup service with localStorage
159→    this.backupService = new DataBackupService<FolderData>('gemini-folders', validateFolderData);
160→
161→    // Note: Data loading moved to init() for async support
162→    // This allows Safari to use async browser.storage API
163→    this.createTooltip();
164→
165→    // Initialize i18n system
166→    initI18n().catch((e) => {
167→      this.debugWarn('Failed to initialize i18n:', e);
168→    });
169→  }
