171→  async init(): Promise<void> {
172→    try {
173→      // Initialize storage adapter (handles migration for Safari automatically)
174→      await this.storage.init(STORAGE_KEY);
175→
176→      // Setup automatic backup before page unload
177→      this.backupService.setupBeforeUnloadBackup(() => this.data);
178→
179→      // Initialize storage quota monitor
180→      const storageMonitor = getStorageMonitor({
181→        checkIntervalMs: 60000, // Check every minute for Gemini (more active)
182→      });
183→
184→      // Use custom notification callback to match our style
185→      storageMonitor.setNotificationCallback((message, level) => {
186→        this.showNotificationByLevel(message, level);
187→      });
188→
189→      // Start monitoring
190→      storageMonitor.startMonitoring();
191→
192→      // Load account isolation setting/scope before reading folder data.
193→      await this.loadAccountIsolationSetting();
194→      await this.refreshAccountScope();
195→
196→      // Load folder data (async, works for both Safari and non-Safari)
197→      await this.loadData();
198→
199→      // Load folder enabled setting
200→      await this.loadFolderEnabledSetting();

