file.content:
.gv-folder-import-dialog {
  background: white;
  border-radius: 16px;
  padding: 24px;
  min-width: 400px;
  max-width: 500px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.12);
  font-family: 'Google Sans', Roboto, Arial, sans-serif;
}

html.dark .gv-folder-import-dialog,
[data-theme='dark'] .gv-folder-import-dialog,
[data-color-scheme='dark'] .gv-folder-import-dialog {
  background: #1e1e1e;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
}

.gv-folder-import-dialog .gv-folder-dialog-title {
  font-size: 20px;
  font-weight: 500;
  margin-bottom: 20px;
  color: #202124;
}

html.dark .gv-folder-import-dialog .gv-folder-dialog-title,
[data-theme='dark'] .gv-folder-import-dialog .gv-folder-dialog-title,
[data-color-scheme='dark'] .gv-folder-import-dialog .gv-folder-dialog-title {
  color: #e8eaed;
}

/* Strategy selection */
.gv-folder-import-strategy {
  margin-bottom: 20px;
}

.gv-folder-import-strategy-label {
  font-size: 14px;
  font-weight: 500;
  margin-bottom: 12px;
  color: #5f6368;
}

html.dark .gv-folder-import-strategy-label,
[data-theme='dark'] .gv-folder-import-strategy-label,
[data-color-scheme='dark'] .gv-folder-import-strategy-label {
  color: #9aa0a6;
}

.gv-folder-import-strategy-options {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.gv-folder-import-radio-option {
  display: flex;
  align-items: center;
  padding: 12px;
  border: 1px solid #dadce0;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.2s ease;
}

.gv-folder-import-radio-option:hover {
  background-color: #f8f9fa;
  border-color: #1a73e8;
}

html.dark .gv-folder-import-radio-option,
[data-theme='dark'] .gv-folder-import-radio-option,
[data-color-scheme='dark'] .gv-folder-import-radio-option {
  border-color: #3c4043;
}

html.dark .gv-folder-import-radio-option:hover,
[data-theme='dark'] .gv-folder-import-radio-option:hover,
[data-color-scheme='dark'] .gv-folder-import-radio-option:hover {
  background-color: #2d2e30;
  border-color: #8ab4f8;
}

.gv-folder-import-radio-option input[type='radio'] {
  margin-right: 12px;
  cursor: pointer;
}

.gv-folder-import-radio-option span {
  font-size: 14px;
  color: #202124;
}

html.dark .gv-folder-import-radio-option span,
[data-theme='dark'] .gv-folder-import-radio-option span,
[data-color-scheme='dark'] .gv-folder-import-radio-option span {
  color: #e8eaed;
}

/* File input */
.gv-folder-import-file-input {
  margin-bottom: 20px;
}

.gv-folder-import-file-button {
  background: #1a73e8;
  color: white;
  border: none;
  padding: 10px 20px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 14px;
  font-weight: 500;
  transition: background-color 0.2s ease;
  width: 100%;
}

.gv-folder-import-file-button:hover {
  background: #1765cc;
}

.gv-folder-import-file-name {
  margin-top: 12px;
  font-size: 13px;
  color: #5f6368;
  padding: 8px;
  background: #f8f9fa;
  border-radius: 4px;
  text-align: center;
  min-height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
}

html.dark .gv-folder-import-file-name,
[data-theme='dark'] .gv-folder-import-file-name,
[data-color-scheme='dark'] .gv-folder-import-file-name {
  background: #2d2e30;
  color: #9aa0a6;
}

/* Dialog buttons */
.gv-folder-dialog-buttons {
  display: flex;
  gap: 12px;
  justify-content: flex-end;
}

.gv-folder-dialog-btn {
  padding: 10px 24px;
  border-radius: 8px;
  border: none;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;
}

.gv-folder-dialog-btn-primary {
  background: #1a73e8;
  color: white;
}

.gv-folder-dialog-btn-primary:hover {
  background: #1765cc;
}

.gv-folder-dialog-btn-secondary {
  background: transparent;
  color: #1a73e8;
  border: 1px solid #dadce0;
}

.gv-folder-dialog-btn-secondary:hover {
  background: #f8f9fa;
}

html.dark .gv-folder-dialog-btn-secondary,
[data-theme='dark'] .gv-folder-dialog-btn-secondary,
[data-color-scheme='dark'] .gv-folder-dialog-btn-secondary {
  color: #8ab4f8;
  border-color: #3c4043;
}

html.dark .gv-folder-dialog-btn-secondary:hover,
[data-theme='dark'] .gv-folder-dialog-btn-secondary:hover,
[data-color-scheme='dark'] .gv-folder-dialog-btn-secondary:hover {
  background: #2d2e30;
}

/* Paste JSON toggle & textarea */
.gv-folder-import-paste-container {
  margin-bottom: 20px;
}

.gv-folder-import-paste-toggle {
  background: transparent;
  color: #1a73e8;
  border: 1px dashed #dadce0;
  padding: 8px 16px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 13px;
  font-weight: 500;
  width: 100%;
  transition: all 0.2s ease;
}

.gv-folder-import-paste-toggle:hover {
  background: #f0f4ff;
  border-color: #1a73e8;
}

.gv-folder-import-paste-toggle-active {
  background: #e8f0fe;
  border-color: #1a73e8;
  border-style: solid;
}

html.dark .gv-folder-import-paste-toggle,
[data-theme='dark'] .gv-folder-import-paste-toggle,
[data-color-scheme='dark'] .gv-folder-import-paste-toggle {
  color: #8ab4f8;
  border-color: #3c4043;
}

html.dark .gv-folder-import-paste-toggle:hover,
[data-theme='dark'] .gv-folder-import-paste-toggle:hover,
[data-color-scheme='dark'] .gv-folder-import-paste-toggle:hover {
  background: #2d2e30;
  border-color: #8ab4f8;
}

html.dark .gv-folder-import-paste-toggle-active,
[data-theme='dark'] .gv-folder-import-paste-toggle-active,
[data-color-scheme='dark'] .gv-folder-import-paste-toggle-active {
  background: #1e3a5f;
  border-color: #8ab4f8;
}

.gv-folder-import-paste-area {
  width: 100%;
  min-height: 120px;
  max-height: 300px;
  margin-top: 10px;
  padding: 10px;
  border: 1px solid #dadce0;
  border-radius: 8px;
  font-family: monospace;
  font-size: 12px;
  line-height: 1.5;
  resize: vertical;
  background: #f8f9fa;
  color: #202124;
  box-sizing: border-box;
}

.gv-folder-import-paste-area:focus {
  outline: none;
  border-color: #1a73e8;
  box-shadow: 0 0 0 2px rgba(26, 115, 232, 0.2);
}

html.dark .gv-folder-import-paste-area,
[data-theme='dark'] .gv-folder-import-paste-area,
[data-color-scheme='dark'] .gv-folder-import-paste-area {
  background: #2d2e30;
  color: #e8eaed;
  border-color: #3c4043;
}

html.dark .gv-folder-import-paste-area:focus,
[data-theme='dark'] .gv-folder-import-paste-area:focus,
[data-color-scheme='dark'] .gv-folder-import-paste-area:focus {
  border-color: #8ab4f8;
  box-shadow: 0 0 0 2px rgba(138, 180, 248, 0.2);
}

