2878→  private confirmRemoveConversation(
2879→    folderId: string,
2880→    conversationId: string,
2881→    title: string,
2882→    event: MouseEvent,
2883→  ): void {
2884→    // Create inline confirmation dialog using safe DOM API
2885→    const confirmDialog = document.createElement('div');
2886→    confirmDialog.className = 'gv-folder-confirm-dialog';
2887→
2888→    // Create message element safely with user-provided title
2889→    const message = document.createElement('div');
2890→    message.className = 'gv-folder-confirm-message';
2891→    // Safe: textContent prevents XSS even with user-controlled title
2892→    message.textContent = this.t('folder_remove_conversation_confirm').replace('{title}', title);
2893→
2894→    // Create actions container
2895→    const actions = document.createElement('div');
2896→    actions.className = 'gv-folder-confirm-actions';
2897→
2898→    // Create buttons safely
2899→    const yesBtn = document.createElement('button');
2900→    yesBtn.className = 'gv-folder-confirm-btn gv-folder-confirm-yes';
2901→    yesBtn.textContent = this.t('pm_delete'); // Safe: uses textContent
2902→
2903→    const noBtn = document.createElement('button');
2904→    noBtn.className = 'gv-folder-confirm-btn gv-folder-confirm-no';
2905→    noBtn.textContent = this.t('pm_cancel'); // Safe: uses textContent
2906→
2907→    // Assemble the dialog
2908→    actions.appendChild(yesBtn);
2909→    actions.appendChild(noBtn);
2910→    confirmDialog.appendChild(message);
2911→    confirmDialog.appendChild(actions);
2912→
2913→    // Position near the clicked element
2914→    const rect = (event.target as HTMLElement).getBoundingClientRect();
2915→    confirmDialog.style.position = 'fixed';
2916→    confirmDialog.style.top = `${rect.bottom + 4}px`;
