.gv-folder-menu {
  background-color: var(--folder-menu-bg);
  border: 1px solid var(--folder-border);
  border-radius: 8px;
  box-shadow: var(--folder-menu-shadow);
  padding: 4px;
  z-index: 2147483647;
  min-width: 160px;
}

.gv-folder-menu-item {
  display: block;
  width: 100%;
  padding: 8px 12px;
  border: none;
  background: transparent;
  color: var(--folder-text);
  text-align: left;
  cursor: pointer;
  border-radius: 4px;
  font-size: 14px;
  transition: background-color 0.2s;
}

.gv-folder-menu-item:hover {
  background-color: var(--folder-hover-bg);
}

/* Color Picker Dialog */
.gv-color-picker-dialog {
  position: fixed;
  background: var(--folder-menu-bg);
  border: 1px solid var(--folder-border);
  border-radius: 12px;
  padding: 12px;
  box-shadow: var(--folder-menu-shadow);
  z-index: 10001;
  display: grid;
