}

/* Make action buttons absolute so they don’t steal inline space */
.gv-aistudio .gv-folder-pin-btn,
.gv-aistudio .gv-folder-actions-btn {
  width: 24px;
  height: 24px;
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  margin: 0;
  overflow: visible;
  z-index: 1;
}

/* Pin button: hidden by default, show on hover to save space */
.gv-aistudio .gv-folder-pin-btn {
  opacity: 0;
  transition: opacity 0.15s ease;
}

/* More button: hidden by default, show on hover to save space */
.gv-aistudio .gv-folder-actions-btn {
  opacity: 0;
  transition: opacity 0.15s ease;
}

