}

.theme-host.dark-theme .gv-folder-menu-item,
body.dark-theme .gv-folder-menu-item {
  color: oklch(0.92 0.004 250);
}

.theme-host.dark-theme .gv-folder-menu-item:hover,
body.dark-theme .gv-folder-menu-item:hover {
  background: oklch(0.92 0.004 250 / 0.08);
}

.theme-host.light-theme .gv-folder-menu-item,
body.light-theme .gv-folder-menu-item {
  color: oklch(0.14 0.004 285);
}

.theme-host.light-theme .gv-folder-menu-item:hover,
body.light-theme .gv-folder-menu-item:hover {
  background: oklch(0.14 0.004 285 / 0.06);
}

/* ── Color Picker Dialog ── */
.gv-color-picker-dialog {
  position: fixed;
  background: oklch(0.995 0.002 250);
  border: 1px solid oklch(0.92 0.004 250 / 0.7);
  border-radius: 14px;
  padding: 12px;
  box-shadow:
    0 12px 40px oklch(0 0 0 / 0.1),
    0 4px 16px oklch(0 0 0 / 0.05);
  z-index: 10001;
  display: grid;
  grid-template-columns: repeat(4, 36px);
  gap: 8px;
  animation: gv-folder-fadeIn 0.15s cubic-bezier(0.4, 0, 0.2, 1);
}

@keyframes gv-folder-fadeIn {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(4px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@media (prefers-color-scheme: dark) {
  .gv-color-picker-dialog {
    background: oklch(0.2 0.008 285);
    border-color: oklch(0.3 0.008 285 / 0.7);
    box-shadow:
      0 12px 40px oklch(0 0 0 / 0.35),
      0 4px 16px oklch(0 0 0 / 0.2);
  }
}

.theme-host.dark-theme .gv-color-picker-dialog,
body.dark-theme .gv-color-picker-dialog {
  background: oklch(0.2 0.008 285);
  border-color: oklch(0.3 0.008 285 / 0.7);
  box-shadow:
    0 12px 40px oklch(0 0 0 / 0.35),
    0 4px 16px oklch(0 0 0 / 0.2);
}

.theme-host.light-theme .gv-color-picker-dialog,
body.light-theme .gv-color-picker-dialog {
  background: oklch(0.995 0.002 250);
  border-color: oklch(0.92 0.004 250 / 0.7);
}

.gv-color-picker-item {
  width: 36px;
  height: 36px;
