}

@media (prefers-color-scheme: dark) {
  .gv-folder-dialog-cancel {
    color: oklch(0.92 0.004 250);
    border-top-color: oklch(0.3 0.008 285 / 0.5);
  }
  .gv-folder-dialog-cancel:hover {
